  "metamarket_collection_cyber_animals": "Кібер-тварини",
  "metamarket_collection_meta_resources": "Мета-ресурси",
  "metamarket_collection_heroes": "Герої",
  "metamarket_collection_meta_space": "МетаКосмос",
